import csv
from collections import defaultdict

customers = {}
with open('customers.csv', newline='') as f:
    for row in csv.DictReader(f):
        customers[row['customer_id']] = row['email']

totals = defaultdict(float)
with open('orders.csv', newline='') as f:
    for row in csv.DictReader(f):
        email = customers.get(row['customer_id'], 'UNKNOWN')
        totals[email] += float(row['amount'])

for email, total in sorted(totals.items(), key=lambda x: -x[1]):
    print(f'{email}\t{total:.2f}')
